package com.cora.stylefinder.member.auth;
import com.cora.stylefinder.member.auth.dto.*; import com.cora.stylefinder.member.member.User; import com.cora.stylefinder.member.member.dto.MemberResponse; import jakarta.validation.Valid; import java.util.Map; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/members") public class AuthController { private final AuthService auth; public AuthController(AuthService auth){this.auth=auth;} @PostMapping("/signup") ResponseEntity<MemberResponse> signup(@Valid @RequestBody SignupRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(auth.signup(r));} @PostMapping("/login") TokenResponse login(@Valid @RequestBody LoginRequest r){return auth.login(r);}@PostMapping("/token/refresh") TokenResponse refresh(@Valid @RequestBody RefreshRequest r){return auth.refresh(r);}@PostMapping("/logout") ResponseEntity<Void> logout(@AuthenticationPrincipal User u,@RequestBody(required=false) Map<String,String> body){auth.logout(u,body==null?null:body.get("refreshToken"));return ResponseEntity.noContent().build();}@GetMapping("/me") MemberResponse me(@AuthenticationPrincipal User u){return auth.me(u);} }
